import{_ as e,c as o,o as s,ah as r}from"./chunks/framework.C-x9UAyH.js";const i="/cloud_productos.png",h=JSON.parse('{"title":"Productos de AWS","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"aws/productos_de_aws.md","filePath":"aws/productos_de_aws.md","lastUpdated":1760459112000}'),t={name:"aws/productos_de_aws.md"};function n(d,a,c,l,m,u){return s(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="productos-de-aws" tabindex="-1">Productos de AWS <a class="header-anchor" href="#productos-de-aws" aria-label="Permalink to &quot;Productos de AWS&quot;">​</a></h1><p>Los productos de AWS son una poderosa herramienta que puede ayudar a las empresas a mejorar su eficiencia, reducir sus costos y aumentar su capacidad de innovación.</p><p align="center"><img src="'+i+'" width="800" alt="aws_productos"></p><h2 id="compute-ec2" tabindex="-1">Compute - EC2 <a class="header-anchor" href="#compute-ec2" aria-label="Permalink to &quot;Compute - EC2&quot;">​</a></h2><p>Proporciona instancias de servidor virtual escalables bajo demanda (máquinas virtuales) que se pueden iniciar, detener y ajustar según sea necesario. Es una opción popular para aplicaciones web, móviles y cargas de trabajo de análisis.</p><h2 id="amazon-ec2-auto-scaling" tabindex="-1">Amazon EC2 Auto scaling <a class="header-anchor" href="#amazon-ec2-auto-scaling" aria-label="Permalink to &quot;Amazon EC2 Auto scaling&quot;">​</a></h2><p>Servicio que permite configurar el escalado automático de instancias EC2. Añade o elimina instancias automáticamente en función de la demanda, lo que garantiza el rendimiento de las aplicaciones y optimiza los costos.</p><h2 id="aws-lambda" tabindex="-1">AWS Lambda <a class="header-anchor" href="#aws-lambda" aria-label="Permalink to &quot;AWS Lambda&quot;">​</a></h2><p>Servicio de computación sin servidor (serverless) que ejecuta funciones en respuesta a eventos, sin necesidad de aprovisionar ni administrar servidores. AWS Lambda escala automáticamente y administra los recursos por ti, ideal para cargas de trabajo basadas en eventos y microservicios.</p><h2 id="storage-s3" tabindex="-1">Storage S3 <a class="header-anchor" href="#storage-s3" aria-label="Permalink to &quot;Storage S3&quot;">​</a></h2><p>Amazon Simple Storage Service (S3) es un servicio de almacenamiento de objetos, seguro, duradero y altamente escalable. Se utiliza para almacenar archivos estáticos como imágenes, documentos, archivos multimedia, copias de seguridad o incluso sitios web estáticos (HTML/CSS/JS). Los datos se almacenan como objetos dentro de <em>buckets</em>.</p><h2 id="amazon-rds" tabindex="-1">Amazon RDS <a class="header-anchor" href="#amazon-rds" aria-label="Permalink to &quot;Amazon RDS&quot;">​</a></h2><p>Relational Database Service (RDS) es un servicio que facilita la creación, operación y escalado de bases de datos relacionales en la nube. Administra tareas como copias de seguridad, parches y replicación. Compatible con motores como MySQL, PostgreSQL, Oracle, SQL Server y MariaDB.</p><h2 id="amazon-dynamodb" tabindex="-1">Amazon DynamoDB <a class="header-anchor" href="#amazon-dynamodb" aria-label="Permalink to &quot;Amazon DynamoDB&quot;">​</a></h2><p>Servicio serverless (SaaS) permite almacenar datos de tipo clave-valor. BD NO SQL. Es un servicio de base de datos noSQL ofrecido por Amazon como parte de Amazon Web Services. DynamoDB expone un modelo de datos similar que deriva su nombre de Dynamo, pero una implementacion subyacente diferente.</p>',15)])])}const b=e(t,[["render",n]]);export{h as __pageData,b as default};
